/**
 * Nodal Analysis Studio - engine validation harness (NA1).
 *
 * Standalone gate runner modeled on tools/validation/welltest: labeled
 * CASES, per-check tolerances stated inline, exit 0 only on full pass.
 * Run from the repo root:
 *
 *   node tools/validation/nodal/run-validation.mjs
 *
 * Prerequisite: goldens generated by the independent Python oracle
 * (python3 tools/validation/nodal/genfixtures.py), committed at
 * src/utils/nodal/__tests__/goldens.json.
 *
 * CASE 1  Moody/Colebrook friction vs the oracle's bisection route
 *         (fixed-point vs bisection; < 0.2 % everywhere, laminar exact)
 * CASE 2  Numerics analytic truths (Brent root of cos x = x, exact
 *         linear fit recovery, interpolation identities)
 * CASE 3  Vogel dimensionless identity and calibration round trip
 *         (the equation itself is the anchor)
 * CASE 4  Oil IPR family vs oracle goldens (composite Standing continuity
 *         and below-pb calibration algebra, Fetkovich, Jones)
 * CASE 5  Black-oil PVT adapter vs oracle across a p, T matrix
 *         (Rs / Bo / muO / Z / Bg / muG / water / densities / sigma)
 * CASE 6  Minimum-curvature trajectory vs oracle + exact arc identities
 * CASE 7  Gas deliverability: JS trapezoid m(p) + Darcy IPR vs the
 *         oracle's Simpson quadrature route (<= 1 %), plus closed-form
 *         back-pressure / LIT identities
 * CASE 8  Published literature fixtures - armed only when book-verified
 *         data is present in literature-fixtures.json (repo precedent:
 *         gates arm only from owner-provided sources)
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

import { brentSolve, linearFit, linearInterp } from '../../../src/utils/nodal/numerics.js';
import { moodyFrictionFactor } from '../../../src/utils/nodal/friction.js';
import { buildFluidModel, pvtAt } from '../../../src/utils/nodal/pvt.js';
import { computeIpr, rateAtPwf } from '../../../src/utils/nodal/ipr.js';
import { buildTrajectory, tvdAtMd } from '../../../src/utils/nodal/trajectory.js';
import { darcyGasIpr, backPressureIpr, litIpr } from '../../../src/utils/nodal/iprGas.js';
import { gradientFor } from '../../../src/utils/nodal/correlations/index.js';
import { beggsBrillHoldupDetail, frictionRatioExponent } from '../../../src/utils/nodal/correlations/beggsBrill.js';
import { fancherBrownFriction } from '../../../src/utils/nodal/correlations/fancherBrown.js';
import { averageTzBhp } from '../../../src/utils/nodal/cullenderSmith.js';
import { solveOperatingPoint, solveGasOperatingPoint } from '../../../src/utils/nodal/system.js';
import { gasLiftScreening } from '../../../src/utils/nodal/gasLift.js';
import { chokeWhp, chokeSize, gasChokeRate, gasChokeUpstream } from '../../../src/utils/nodal/chokes.js';
import { linearGeothermal } from '../../../src/utils/nodal/temperature.js';
import { bhpFromWhp } from '../../../src/utils/nodal/traverse.js';
import { cullenderSmithBhp } from '../../../src/utils/nodal/cullenderSmith.js';

const here = path.dirname(fileURLToPath(import.meta.url));
const goldens = JSON.parse(
  fs.readFileSync(path.join(here, '../../../src/utils/nodal/__tests__/goldens.json'), 'utf8')
);
const literature = JSON.parse(
  fs.readFileSync(path.join(here, 'literature-fixtures.json'), 'utf8')
);

let passed = 0;
let failed = 0;

const check = (name, actual, expected, relTol, unit = '') => {
  const err = Math.abs(actual - expected) / Math.max(Math.abs(expected), 1e-300);
  const ok = Number.isFinite(actual) && err <= relTol;
  const detail = `${actual}${unit ? ` ${unit}` : ''} vs ${expected}${unit ? ` ${unit}` : ''} (rel err ${err.toExponential(2)}, tol ${relTol})`;
  console.log(`  ${ok ? 'PASS' : 'FAIL'}  ${name}: ${detail}`);
  if (ok) passed += 1; else failed += 1;
};

const banner = (t) => console.log(`\n=== ${t} ===`);

// ---------------------------------------------------------------------------
banner('CASE 1: Moody/Colebrook friction vs oracle bisection route');
for (const c of goldens.friction) {
  const f = moodyFrictionFactor(c.re, c.relRough);
  check(`f(Re=${c.re}, rr=${c.relRough})`, f, c.f, 2e-3);
}

// ---------------------------------------------------------------------------
banner('CASE 2: numerics analytic truths');
{
  const dottie = brentSolve((x) => Math.cos(x) - x, 0, 1, { tol: 1e-14 });
  check('Brent root of cos x = x (Dottie number)', dottie.root, 0.7390851332151607, 1e-9);
  const fit = linearFit([1, 2, 3, 4, 5], [2.5, 4.5, 6.5, 8.5, 10.5]);
  check('linearFit slope on exact line', fit.slope, 2, 1e-12);
  check('linearFit intercept on exact line', fit.intercept, 0.5, 1e-12);
  check('linearInterp midpoint identity', linearInterp([0, 10], [100, 200], 5), 150, 1e-12);
}

// ---------------------------------------------------------------------------
banner('CASE 3: Vogel dimensionless identity + calibration round trip');
{
  const v = goldens.ipr.vogel;
  const ipr = computeIpr({ model: 'vogel', pr: v.pr, qmax: v.qmax });
  for (const p of v.points) {
    check(`Vogel q(pwf=${p.pwf})`, rateAtPwf(ipr, p.pwf), p.q, 1e-12, 'stb/d');
  }
  const cal = computeIpr({ model: 'vogel', pr: v.pr, testPoint: { q: 700, pwf: 1000 } });
  check('Vogel qmax calibrated from (700, 1000)', cal.qmax, 1000, 1e-9, 'stb/d');
}

// ---------------------------------------------------------------------------
banner('CASE 4: oil IPR family vs oracle goldens');
{
  const c = goldens.ipr.composite;
  const ipr = computeIpr({ model: 'composite', pr: c.pr, pb: c.pb, pi: c.pi });
  for (const p of c.points) {
    check(`composite q(pwf=${p.pwf})`, rateAtPwf(ipr, p.pwf), p.q, 1e-9, 'stb/d');
  }
  const qTest = rateAtPwf(ipr, 1500);
  const cal = computeIpr({ model: 'composite', pr: c.pr, pb: c.pb, testPoint: { q: qTest, pwf: 1500 } });
  check('composite J from below-pb test point', cal.pi, c.jFromTestBelowPb, 1e-9, 'stb/d/psi');

  const f = goldens.ipr.fetkovich;
  const fIpr = computeIpr({ model: 'fetkovich', pr: f.pr, c: f.c, n: f.n });
  for (const p of f.points) {
    check(`fetkovich q(pwf=${p.pwf})`, rateAtPwf(fIpr, p.pwf), p.q, 1e-9, 'stb/d');
  }

  const j = goldens.ipr.jones;
  const jIpr = computeIpr({ model: 'jones', pr: j.pr, a: j.a, b: j.b });
  for (const p of j.points) {
    check(`jones q(pwf=${p.pwf})`, rateAtPwf(jIpr, p.pwf), p.q, 1e-9, 'stb/d');
  }
}

// ---------------------------------------------------------------------------
banner('CASE 5: black-oil PVT adapter vs oracle across p, T matrix');
{
  const model = buildFluidModel({
    api: goldens.model.api,
    gasSg: goldens.model.gasSg,
    gor: goldens.model.gor,
    salinityPpm: goldens.model.salinityPpm,
  });
  for (const c of goldens.pvt) {
    const js = pvtAt(model, c.p, c.tF);
    const label = `p=${c.p} T=${c.tF}`;
    check(`${label} pb`, js.pb, c.props.pb, 2e-3, 'psia');
    check(`${label} rs`, js.rs, c.props.rs, 2e-3, 'scf/stb');
    check(`${label} bo`, js.bo, c.props.bo, 1e-3, 'rb/stb');
    check(`${label} muO`, js.muO, c.props.muO, 5e-3, 'cp');
    check(`${label} z`, js.z, c.props.z, 1e-9);
    check(`${label} muG`, js.muG, c.props.muG, 1e-9, 'cp');
    check(`${label} bw`, js.bw, c.props.bw, 1e-9, 'rb/stb');
    check(`${label} muW`, js.muW, c.props.muW, 1e-9, 'cp');
    check(`${label} rhoO`, js.rhoO, c.props.rhoO, 1e-3, 'lbm/ft3');
    check(`${label} rhoG`, js.rhoG, c.props.rhoG, 1e-9, 'lbm/ft3');
    check(`${label} rhoW`, js.rhoW, c.props.rhoW, 1e-9, 'lbm/ft3');
    check(`${label} sigmaOG`, js.sigmaOG, c.props.sigmaOG, 1e-9, 'dyn/cm');
    check(`${label} sigmaWG`, js.sigmaWG, c.props.sigmaWG, 1e-9, 'dyn/cm');
  }
}

// ---------------------------------------------------------------------------
banner('CASE 6: minimum-curvature trajectory vs oracle + exact arcs');
{
  const t = goldens.trajectory;
  const traj = buildTrajectory({ mode: 'deviated', survey: t.survey });
  t.survey.forEach((s, i) => {
    check(`TVD at md ${s.md}`, tvdAtMd(traj, s.md), t.tvds[i], 1e-9, 'ft');
  });
  const quarter = buildTrajectory({
    mode: 'deviated',
    survey: [{ md: 0, inc: 0, azi: 0 }, { md: 900, inc: 90, azi: 0 }],
  });
  check('quarter-circle arc TVD = 2 dMd / pi', quarter.tvdMax, (2 * 900) / Math.PI, 1e-9, 'ft');
  const vertical = buildTrajectory({ mode: 'vertical', depthFt: 8500 });
  check('vertical identity TVD', vertical.tvdMax, 8500, 1e-12, 'ft');
}

// ---------------------------------------------------------------------------
banner('CASE 7: gas deliverability vs oracle Simpson route + closed forms');
{
  const g = goldens.gasIpr;
  // nPoints 7 makes the JS pwf grid land exactly on the golden pwfs
  // (3000, 2500, ..., 0), so the comparison needs no interpolation.
  const js = darcyGasIpr({ ...g.base, nPoints: 7 });
  for (const p of g.points) {
    if (p.q <= 0) continue;
    const qJs = js.curve.find((pt) => Math.abs(pt.pwf - p.pwf) < 1e-6)?.q;
    check(`darcy gas q(pwf=${p.pwf})`, qJs, p.q, 1.5e-2, 'Mscf/d');
  }
  const bp = backPressureIpr({ pr: 3000, c: 2e-4, n: 0.85 });
  check('back-pressure AOF closed form', bp.aof, 2e-4 * Math.pow(3000 ** 2, 0.85), 1e-12, 'Mscf/d');
  const lit = litIpr({ pr: 3000, a: 0.05, b: 5e-6 });
  check('LIT AOF inverts its quadratic', 0.05 * lit.aof + 5e-6 * lit.aof * lit.aof, 3000 ** 2, 1e-9, 'psi2');
}

// ---------------------------------------------------------------------------
banner('CASE 9: NA2 gradient correlations vs oracle transcription');
{
  for (const c of goldens.gradients) {
    const js = gradientFor(c.correlation)({
      p: c.p,
      thetaDeg: c.thetaDeg,
      dIn: c.dIn,
      rough: c.rough,
      flows: c.flows,
      pvt: { rhoG: 5.0, muG: 0.015 },
      glr: c.glr,
    });
    const label = `${c.correlation} vsl=${c.flows.vsl} vsg=${c.flows.vsg} th=${c.thetaDeg}`;
    // Holdup algebra is closed form (equality); dpdz carries the Colebrook
    // route difference (< 0.2 %).
    check(`${label} holdup`, js.holdup, c.out.holdup, 1e-9);
    check(`${label} dpdz`, js.dpdz, c.out.dpdz, 2e-3, 'psi/ft');
    if (js.pattern !== c.out.pattern) {
      console.log(`  FAIL  ${label} pattern: ${js.pattern} vs ${c.out.pattern}`);
      failed += 1;
    } else {
      passed += 1;
    }
  }
}

// ---------------------------------------------------------------------------
banner('CASE 10: traverse vs oracle RK4 route (Heun 50 ft vs RK4 5 ft)');
{
  const model = buildFluidModel({
    api: goldens.model.api,
    gasSg: goldens.model.gasSg,
    gor: goldens.model.gor,
    salinityPpm: goldens.model.salinityPpm,
  });
  for (const c of goldens.traverse) {
    const trajectory = c.survey
      ? buildTrajectory({ mode: 'deviated', survey: c.survey })
      : buildTrajectory({ mode: 'vertical', depthFt: c.nodeMd });
    const res = bhpFromWhp({
      fluidModel: model,
      rates: c.rates,
      trajectory,
      tAt: linearGeothermal({ whtF: c.whtF, bhtF: c.bhtF, tvdMaxFt: c.tvdMax }),
      idIn: c.idIn,
      roughnessIn: c.roughnessIn,
      correlation: c.correlation,
      whp: c.whp,
      nodeMd: c.nodeMd,
      stepFt: 50,
    });
    check(`${c.label} BHP`, res.pEnd, c.bhp, 3e-3, 'psia');
  }
}

// ---------------------------------------------------------------------------
banner('CASE 11: Cullender-Smith quadrature vs oracle RK4 ODE route');
{
  for (const c of goldens.cullenderSmith) {
    const res = cullenderSmithBhp(c);
    check(`${c.label} pwf`, res.pwf, c.pwf, 5e-3, 'psia');
    if (!res.converged) {
      console.log(`  FAIL  ${c.label}: iteration did not converge`);
      failed += 1;
    } else {
      passed += 1;
    }
  }
}

// ---------------------------------------------------------------------------
banner('CASE 12: operating point vs oracle bisection + RK4 route');
{
  const model = buildFluidModel({
    api: goldens.model.api,
    gasSg: goldens.model.gasSg,
    gor: goldens.model.gor,
    salinityPpm: goldens.model.salinityPpm,
  });
  for (const c of goldens.operatingPoint.oil) {
    const ipr = computeIpr({ model: 'composite', pr: c.ipr.pr, pb: c.ipr.pb, pi: c.ipr.pi });
    const trajectory = buildTrajectory({ mode: 'vertical', depthFt: c.vlp.nodeMd });
    const res = solveOperatingPoint({
      ipr,
      vlp: {
        fluidModel: model,
        rates: c.vlp.rates,
        trajectory,
        tAt: linearGeothermal({ whtF: c.vlp.whtF, bhtF: c.vlp.bhtF, tvdMaxFt: c.vlp.tvdMax }),
        idIn: c.vlp.idIn,
        roughnessIn: c.vlp.roughnessIn,
        correlation: c.vlp.correlation,
        whp: c.vlp.whp,
        nodeMd: c.vlp.nodeMd,
        stepFt: 50,
      },
    });
    if (res.status !== 'flowing') {
      console.log(`  FAIL  ${c.label}: status ${res.status}, expected flowing`);
      failed += 1;
    } else {
      passed += 1;
      check(`${c.label} q`, res.op.q, c.op.q, 1e-2, 'stb/d');
      check(`${c.label} pwf`, res.op.pwf, c.op.pwf, 1e-2, 'psia');
    }
  }
  {
    const g = goldens.operatingPoint.gas;
    const iprResult = backPressureIpr({ pr: g.ipr.pr, c: g.ipr.c, n: g.ipr.n, nPoints: 80 });
    const res = solveGasOperatingPoint({ iprResult, vlp: g.cs, nGrid: 60 });
    if (res.status !== 'flowing') {
      console.log(`  FAIL  ${g.label}: status ${res.status}, expected flowing`);
      failed += 1;
    } else {
      passed += 1;
      check(`${g.label} q`, res.op.q, g.op.q, 2e-2, 'Mscf/d');
      check(`${g.label} pwf`, res.op.pwf, g.op.pwf, 2e-2, 'psia');
    }
  }
}

// ---------------------------------------------------------------------------
banner('CASE 13: choke closed forms vs oracle transcription');
{
  for (const c of goldens.chokes.whp) {
    const js = chokeWhp({ q: c.q, glr: c.glr, s64: c.s64, correlation: c.correlation });
    check(`${c.correlation} pwh(q=${c.q}, R=${c.glr}, S=${c.s64})`, js.pwh, c.pwh, 1e-12, 'psia');
    check(`${c.correlation} size round trip`, chokeSize({ pwh: js.pwh, q: c.q, glr: c.glr, correlation: c.correlation }), c.size, 1e-9, '64ths');
  }
  for (const c of goldens.chokes.gas) {
    const js = gasChokeRate(c);
    check(`gas choke q (pUp=${c.pUp}, pDn=${c.pDn})`, js.qMscfd, c.out.qMscfd, 1e-12, 'Mscf/d');
    check(`gas choke tDn (pUp=${c.pUp})`, js.tDnF + 460, c.out.tDnF + 460, 1e-12, 'degR');
    if (js.regime !== c.out.regime) {
      console.log(`  FAIL  gas choke regime: ${js.regime} vs ${c.out.regime}`);
      failed += 1;
    } else {
      passed += 1;
    }
  }
  for (const c of goldens.chokes.upstream) {
    const js = gasChokeUpstream(c);
    check(`gas choke pUp (q=${c.qMscfd})`, js.pUp, c.out.pUp, 1e-6, 'psia');
    if (js.regime !== c.out.regime) {
      console.log(`  FAIL  gas choke upstream regime: ${js.regime} vs ${c.out.regime}`);
      failed += 1;
    } else {
      passed += 1;
    }
  }
}

// ---------------------------------------------------------------------------
banner('CASE 14: gas-lift screening vs oracle route + concavity');
{
  const gl = goldens.gasLift;
  const liftModel = buildFluidModel(gl.model);
  const ipr = computeIpr({ model: 'composite', pr: gl.ipr.pr, pb: gl.ipr.pb, pi: gl.ipr.pi });
  const trajectory = buildTrajectory({ mode: 'vertical', depthFt: gl.vlp.nodeMd });
  const result = gasLiftScreening({
    ipr,
    vlp: {
      fluidModel: liftModel,
      rates: gl.vlp.rates,
      trajectory,
      tAt: linearGeothermal({ whtF: gl.vlp.whtF, bhtF: gl.vlp.bhtF, tvdMaxFt: gl.vlp.tvdMax }),
      idIn: gl.vlp.idIn,
      roughnessIn: gl.vlp.roughnessIn,
      correlation: gl.vlp.correlation,
      whp: gl.vlp.whp,
      nodeMd: gl.vlp.nodeMd,
      stepFt: 50,
    },
    qgis: gl.response.map((p) => p.qgi),
  });
  for (let i = 0; i < gl.response.length; i += 1) {
    const oracleQ = gl.response[i].q;
    const jsQ = result.response[i].q;
    if (oracleQ === 0) {
      if (jsQ !== 0) {
        console.log(`  FAIL  gas-lift qgi ${gl.response[i].qgi}: JS flows (${jsQ}) where oracle is dead`);
        failed += 1;
      } else {
        console.log(`  PASS  gas-lift qgi ${gl.response[i].qgi}: dead on both routes`);
        passed += 1;
      }
    } else {
      check(`gas-lift q at qgi ${gl.response[i].qgi}`, jsQ, oracleQ, 1.5e-2, 'stb/d');
    }
  }
  // Concavity: incremental gains never grow along the lifted branch.
  const lifted = result.response.filter((p) => p.qgi > 0);
  let concave = true;
  for (let i = 2; i < lifted.length; i += 1) {
    const s1 = (lifted[i - 1].q - lifted[i - 2].q) / (lifted[i - 1].qgi - lifted[i - 2].qgi);
    const s2 = (lifted[i].q - lifted[i - 1].q) / (lifted[i].qgi - lifted[i - 1].qgi);
    if (s2 > s1 + 1e-6) concave = false;
  }
  if (concave) {
    console.log('  PASS  gas-lift response concavity: incremental gains never increase');
    passed += 1;
  } else {
    console.log('  FAIL  gas-lift response is not concave');
    failed += 1;
  }
}

// ---------------------------------------------------------------------------
banner('CASE 8: published literature fixtures');
{
  const armed = (literature.fixtures || []).filter((f) => f.armed);
  if (armed.length === 0) {
    console.log('  SKIP  no armed literature fixtures yet; gates arm when book-verified data is committed');
  }
  for (const f of armed) {
    const tol = f.relTol;
    if (f.type === 'cullenderSmith') {
      const res = cullenderSmithBhp(f.inputs);
      check(`${f.id} pwf`, res.pwf, f.expect.pwf, tol, 'psia');
      if (f.expect.pmf) check(`${f.id} pmf`, res.pmf, f.expect.pmf, tol, 'psia');
    } else if (f.type === 'averageTz') {
      const res = averageTzBhp(f.inputs);
      check(`${f.id} pwf`, res.pwf, f.expect.pwf, tol, 'psia');
    } else if (f.type === 'bbHoldupChain') {
      const { lambdaL, nfr, nlv, thetaDeg } = f.inputs;
      const d = beggsBrillHoldupDetail(lambdaL, nfr, nlv, thetaDeg, false);
      if (d.pattern !== f.expect.pattern) {
        console.log(`  FAIL  ${f.id} pattern: ${d.pattern} vs ${f.expect.pattern}`);
        failed += 1;
      } else {
        passed += 1;
      }
      check(`${f.id} HL(0)`, d.hl0, f.expect.hl0, tol);
      check(`${f.id} psi`, d.psi, f.expect.psi, tol);
      check(`${f.id} HL(theta)`, d.holdup, f.expect.holdup, tol);
      const y = lambdaL / (d.holdup * d.holdup);
      check(`${f.id} y`, y, f.expect.y, tol);
      check(`${f.id} ftp/fn`, Math.exp(frictionRatioExponent(y)), f.expect.ftpOverFn, tol);
    } else if (f.type === 'chokeWhp') {
      check(`${f.id} pwh`, chokeWhp(f.inputs).pwh, f.expect.pwh, tol, 'psia');
    } else if (f.type === 'gasChokeRate') {
      const res = gasChokeRate(f.inputs);
      check(`${f.id} q`, res.qMscfd, f.expect.qMscfd, tol, 'Mscf/d');
      if (res.regime !== f.expect.regime) {
        console.log(`  FAIL  ${f.id} regime: ${res.regime} vs ${f.expect.regime}`);
        failed += 1;
      } else {
        passed += 1;
      }
      if (Math.abs(res.tDnF - f.expect.tDnF) <= (f.tDnTolF ?? 1)) {
        console.log(`  PASS  ${f.id} tDn: ${res.tDnF.toFixed(1)} F vs ${f.expect.tDnF} F (abs tol ${f.tDnTolF ?? 1} F)`);
        passed += 1;
      } else {
        console.log(`  FAIL  ${f.id} tDn: ${res.tDnF.toFixed(1)} F vs ${f.expect.tDnF} F`);
        failed += 1;
      }
    } else if (f.type === 'gasChokeUpstream') {
      const res = gasChokeUpstream(f.inputs);
      check(`${f.id} pUp`, res.pUp, f.expect.pUp, tol, 'psia');
      check(`${f.id} pUpSonicMin`, res.pUpSonicMin, f.expect.pUpSonicMin, tol, 'psia');
      check(`${f.id} qAtSonicMin`, res.qAtSonicMin, f.expect.qAtSonicMin, tol, 'Mscf/d');
      if (res.regime !== f.expect.regime) {
        console.log(`  FAIL  ${f.id} regime: ${res.regime} vs ${f.expect.regime}`);
        failed += 1;
      } else {
        passed += 1;
      }
    } else if (f.type === 'fbFriction') {
      check(`${f.id} f`, fancherBrownFriction(f.inputs.drhov, f.inputs.glr), f.expect.f, tol);
    } else if (f.type === 'mhbGradient') {
      const js = gradientFor('hagedornBrown')({
        p: f.inputs.p,
        thetaDeg: f.inputs.thetaDeg,
        dIn: f.inputs.dIn,
        rough: f.inputs.rough,
        flows: f.inputs.flows,
        pvt: { rhoG: f.inputs.rhoG, muG: f.inputs.muG },
      });
      check(`${f.id} dpdz`, js.dpdz, f.expect.dpdz, tol, 'psi/ft');
    } else {
      console.log(`  FAIL  armed fixture "${f.id}" has unknown type "${f.type}"`);
      failed += 1;
    }
  }
  for (const f of (literature.fixtures || []).filter((x) => !x.armed)) {
    console.log(`  SKIP  ${f.id} (unarmed: ${f.verification})`);
  }
}

// ---------------------------------------------------------------------------
banner('CASE 15: performance smoke (generous budgets, observed times printed)');
{
  const model = buildFluidModel({
    api: goldens.model.api,
    gasSg: goldens.model.gasSg,
    gor: goldens.model.gor,
    salinityPpm: goldens.model.salinityPpm,
  });
  const trajectory = buildTrajectory({ mode: 'vertical', depthFt: 8000 });
  const tAt = linearGeothermal({ whtF: 100, bhtF: 180, tvdMaxFt: 8000 });
  const vlp = {
    fluidModel: model,
    rates: { wct: 0.2, gor: 600 },
    trajectory,
    tAt,
    idIn: 2.441,
    roughnessIn: 0.0006,
    correlation: 'beggsBrill',
    whp: 250,
    nodeMd: 8000,
    stepFt: 50,
  };
  const ipr = computeIpr({ model: 'composite', pr: 3200, pb: 2400, pi: 1.2 });

  const timed = (label, budgetMs, fn) => {
    const t0 = process.hrtime.bigint();
    fn();
    const ms = Number(process.hrtime.bigint() - t0) / 1e6;
    const ok = ms <= budgetMs;
    console.log(`  ${ok ? 'PASS' : 'FAIL'}  time ${label}: ${ms.toFixed(1)} ms (budget ${budgetMs} ms)`);
    if (ok) passed += 1; else failed += 1;
  };

  timed('single traverse, 50 ft steps over 8000 ft', 500, () => {
    bhpFromWhp({ ...vlp, rates: { ...vlp.rates, qo: 800 } });
  });
  timed('operating point solve (UI workload: nGrid 25, 200 ft steps)', 3000, () => {
    solveOperatingPoint({ ipr, vlp: { ...vlp, stepFt: 200 }, nGrid: 25 });
  });
  timed('gas-lift screening, 5 injection points (explicit-run workload)', 20000, () => {
    gasLiftScreening({ ipr, vlp: { ...vlp, stepFt: 200 }, qgis: [0, 400, 800, 1200, 1600], nGrid: 25 });
  });
  timed('Cullender-Smith flowing BHP', 200, () => {
    cullenderSmithBhp({ ptf: 2000, gasSg: 0.75, mdFt: 10000, whtF: 110, bhtF: 245, qMmscfd: 4.915, idIn: 2.441 });
  });
  timed('1000 choke evaluations (keystroke closed forms)', 200, () => {
    for (let i = 0; i < 1000; i += 1) {
      chokeWhp({ q: 400 + i, glr: 800, s64: 12 });
      gasChokeRate({ pUp: 800, pDn: 200, dIn: 1, gasSg: 0.6, tUpF: 75, k: 1.3, cd: 0.62 });
    }
  });
}

// ---------------------------------------------------------------------------
console.log(`\n${failed === 0 ? 'ALL GATES PASS' : 'GATES FAILED'}: ${passed} passed, ${failed} failed`);
process.exit(failed === 0 ? 0 : 1);
